            v4 = AdvSimd.BitwiseSelect(Vector128.Create((byte)0xFF, 0xFF, 0xFF, 0xFF, 0x00, 0x00, 0x00, 0x00, 0xFF, 0xFF, 0xFF, 0xFF, 0x00, 0x00, 0x00, 0x00), maxs4, mins4);
            var shuffled5 = AdvSimd.Arm64.VectorTableLookup(tableB, Vector128.Create((byte)0x0C, 0x0D, 0x0E, 0x0F, 0x18, 0x19, 0x1A, 0x1B, 0x14, 0x15, 0x16, 0x17, 0x20, 0x21, 0x22, 0x23));
            var mins5 = AdvSimd.Min(v5.AsSingle(), shuffled5.AsSingle()).AsByte();
            var maxs5 = AdvSimd.Max(v5.AsSingle(), shuffled5.AsSingle()).AsByte();
            v5 = AdvSimd.BitwiseSelect(Vector128.Create((byte)0xFF, 0xFF, 0xFF, 0xFF, 0x00, 0x00, 0x00, 0x00, 0xFF, 0xFF, 0xFF, 0xFF, 0x00, 0x00, 0x00, 0x00), maxs5, mins5);
            var shuffled6 = AdvSimd.Arm64.VectorTableLookup(tableB, Vector128.Create((byte)0x1C, 0x1D, 0x1E, 0x1F, 0x24, 0x25, 0x26, 0x27, 0x28, 0x29, 0x2A, 0x2B, 0x2C, 0x2D, 0x2E, 0x2F));
            var mins6 = AdvSimd.Min(v6.AsSingle(), shuffled6.AsSingle()).AsByte();
            var maxs6 = AdvSimd.Max(v6.AsSingle(), shuffled6.AsSingle()).AsByte();
            v6 = AdvSimd.BitwiseSelect(Vector128.Create((byte)0xFF, 0xFF, 0xFF, 0xFF, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00), maxs6, mins6);
        }

        v6.StoreUnsafe(ref Unsafe.Add(ref first, 96));
        v5.StoreUnsafe(ref Unsafe.Add(ref first, 80));
        v4.StoreUnsafe(ref Unsafe.Add(ref first, 64));
        v3.StoreUnsafe(ref Unsafe.Add(ref first, 48));
        v2.StoreUnsafe(ref Unsafe.Add(ref first, 32));
        v1.StoreUnsafe(ref Unsafe.Add(ref first, 16));
        v0.StoreUnsafe(ref first);
    }
}
